class Dog:
    def speak(self): return 'Woof!'

class Cat:
    def speak(self): return 'Meow!'

class Duck:
    def speak(self): return 'Quack!'

# Polymorphic function — works with any class that has .speak()
def animal_chorus(animals):
    for animal in animals:
        print(animal.speak())

party = [Dog(), Cat(), Duck(), Dog()]
animal_chorus(party)
# Woof!
# Meow!
# Quack!
# Woof!

