class Circle:
    def __init__(self, r): self.r = r
    def area(self): return 3.14159 * self.r ** 2
class Rectangle:
    def __init__(self, w, h): self.w = w; self.h = h
    def area(self): return self.w * self.h
def total_area(shapes):
    return sum(s.area() for s in shapes)
result = total_area([Rectangle(4, 6), Rectangle(5, 12)])
assert result == 84.0

def describe(obj):
    if hasattr(obj, 'describe'):
        return obj.describe()
    return 'no description'
class Apple:
    def describe(self): return 'A red apple'
assert describe(Apple()) == 'A red apple'
assert describe(42) == 'no description'
